export function getShuffledQuestions(game: string, language: string, difficulty: string, count: number = 5): GameQuestion[] {
  const filtered = Q.filter(q => q.game === game && q.language === language && q.difficulty === difficulty);
  // Deduplicate by code content to prevent repeated questions
  const seen = new Set<string>();
  const unique = filtered.filter(q => {
    const key = q.code.trim();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
  const shuffled = [...unique].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}
